var myDog = new Dog();

// Указывает на функцию-конструктор "Dog"
myDog.constructor;

// Указывает на определение класса "Dog" (его прототип)
myDog.constructor.prototype;
myDog.__proto__;
myDog["__proto__"];

// Приложение хранит настройки в объекте:
let config = {
    isAdmin: false
};

// Атакующий добавляет isAdmin прямо в Object.prototype,
// и теперь любой объект без своего isAdmin вернёт true:
Object.prototype.isAdmin = true;
